SELECT sku, path, brand, name, series, model, category_id, json_extract(properties,'$.cleaner_type') AS cleaner_type, json_extract(properties,'$.screw_type') AS screw_type, json_extract(properties,'$.diameter_mm') AS diameter_mm, json_extract(properties,'$.fastener_type') AS fastener_type, json_extract(properties,'$.storage_type') AS storage_type
FROM products
WHERE (
  brand='Ajax' AND name='Cleaning Liquid' AND series='Ajax Eco Classic' AND model='25C-DXE' AND json_extract(properties,'$.cleaner_type')='degreaser'
) OR (
  brand='Heco' AND name='Wood and Drywall Screw' AND series='Heco Zinc Plated TopFix' AND model='GTU-YPJ' AND json_extract(properties,'$.screw_type')='wood screw' AND CAST(json_extract(properties,'$.diameter_mm') AS REAL)=6
) OR (
  brand='Heco' AND name='Nut Bolt and Washer' AND series='Heco Zinc Plated HECO' AND model='3DW-64B' AND json_extract(properties,'$.fastener_type')='threaded rod'
) OR (
  brand='Heco' AND name='Nut Bolt and Washer' AND series='Heco Zinc Plated HECO' AND model='3DW-64B' AND json_extract(properties,'$.fastener_type')='bolt' AND CAST(json_extract(properties,'$.diameter_mm') AS REAL)=8
) OR (
  brand='Ajax' AND name='Cleaning Liquid' AND series='Ajax Eco Classic' AND model='25C-DXE' AND json_extract(properties,'$.cleaner_type')='floor cleaner'
) OR (
  brand='Festool' AND name='Tool Box and Bag' AND series='Festool Stackable SYS' AND model='3JJ-9LM' AND json_extract(properties,'$.storage_type')='tool bag'
)
LIMIT 20;

